                                                        String viewBox,
                                                        String aspectRatio,
                                                        float w,
                                                        float h,
                                                        BridgeContext ctx) {

        // no viewBox specified
        if (viewBox.length() == 0) {
            return new AffineTransform();
        }
        float[] vb = parseViewBoxAttribute(e, viewBox, ctx);

        // 'preserveAspectRatio' attribute
        PreserveAspectRatioParser p = new PreserveAspectRatioParser();
